// Solution as follows

#include <stdio.h>

int main()
{
    int t;
    scanf("%d", &t); // Use scanf instead of cin in C

    while (t--)
    {
        int A, B, C;
        scanf("%d %d", &A, &C); // Use scanf instead of cin in C

        if (A % 2 == 0 && C % 2 == 0)
        {
            B = (A + C) / 2;
            printf("%d\n", B); // Use printf instead of cout in C
        }
        else if (A % 2 != 0 && C % 2 != 0)
        {
            B = (A + C) / 2;
            printf("%d\n", B); // Use printf instead of cout in C
        }
        else
        {
            printf("-1\n"); // Use printf instead of cout in C
        }
    }

    return 0;
}

